---
import type { ImageMetadata } from "astro"
import { Image } from "astro:assets"
import ArrowRightIcon from "lucide-static/icons/arrow-right.svg"

import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"
import { Section, SectionContainer } from "@/components/ui/section"

type Props = {
  class?: string
  title: string
  description?: string
  buttons?: {
    label: string
    href: string
    variant?: "default" | "outline" | "secondary" | "ghost"
  }[]
  services: {
    image: {
      src: ImageMetadata
      alt: string
    }
    title: string
    description: string
    href?: string
  }[]
}

const { class: className, title, description, buttons, services } = Astro.props
---

<Section class={cn("", className)}>
  <SectionContainer class="gap-8">
    <div
      class="flex flex-col gap-4 md:flex-row md:items-end md:justify-between"
    >
      <div class="max-w-2xl">
        <h2
          class="text-3xl font-semibold tracking-tight text-balance sm:text-4xl"
        >
          {title}
        </h2>
        {
          description && (
            <p class="text-muted-foreground mt-4 text-base leading-relaxed text-balance">
              {description}
            </p>
          )
        }
      </div>
      {
        buttons?.length && (
          <div class="flex flex-wrap gap-3">
            {buttons.map(({ href, label, ...button }) => (
              <Button as="a" href={href} variant={button.variant}>
                {label}
              </Button>
            ))}
          </div>
        )
      }
    </div>
    <div class="grid gap-6 sm:grid-cols-2 lg:grid-cols-4">
      {
        services.map((service) => (
          <article class="group/service flex flex-col gap-4">
            <Image
              src={service.image.src}
              alt={service.image.alt}
              class="aspect-16/10 w-full rounded-lg object-cover"
              widths={[320, 480, 640]}
              sizes="(min-width: 1024px) 25vw, (min-width: 640px) 50vw, 100vw"
            />
            <div class="flex flex-1 flex-col gap-1">
              <h3 class="text-base font-medium">{service.title}</h3>
              <p class="text-muted-foreground text-sm leading-relaxed">
                {service.description}
              </p>
            </div>
            {service.href && (
              <a
                href={service.href}
                class="text-primary inline-flex items-center gap-1.5 text-sm font-medium"
              >
                Learn more
                <ArrowRightIcon class="size-3.5 transition-transform group-hover/service:translate-x-1" />
              </a>
            )}
          </article>
        ))
      }
    </div>
  </SectionContainer>
</Section>
